+package github.chains;
+
+import spoon.Launcher;
+import spoon.processing.AbstractProcessor;
+import spoon.reflect.code.CtBlock;
+import spoon.reflect.code.CtConstructorCall;
+import spoon.reflect.code.CtExpression;
+import spoon.reflect.code.CtInvocation;
+import spoon.reflect.code.CtLocalVariable;
+import spoon.reflect.code.CtStatement;
+import spoon.reflect.declaration.CtElement;
+import spoon.reflect.declaration.CtExecutableReference;
+import spoon.reflect.declaration.CtFieldReference;
+import spoon.reflect.declaration.CtMethod;
+import spoon.reflect.reference.CtTypeReference;
+
+import java.util.ArrayList;
+import java.util.HashMap;
+import java.util.HashSet;
+import java.util.List;
+import java.util.Map;
+import java.util.Set;
+
+public class Main {
+    private static final String OLD_FLYWAY = "org.flywaydb.core.Flyway";
+    private static final String NEW_FLYWAY = "org.flywaydb.core.Flyway";
+
+    public static void main(String[] args) {
+        if (args.length != 2) {
+            throw new IllegalArgumentException("Usage: <input-src-dir> <output-src-dir>");
+        }
+
+        Launcher launcher = new Launcher();
+        launcher.getEnvironment().setNoClasspath(true);
+        launcher.getEnvironment().setAutoImports(true);
+        launcher.addInputResource(args[0]);
+        launcher.setSourceOutputDirectory(args[1]);
+        launcher.addProcessor(new FlywayProcessor());
+        launcher.buildModel();
+        launcher.process();
+        launcher.prettyprint();
+    }
+
+    private static final class FlywayProcessor extends AbstractProcessor<CtTypeReference<?>> {
+        @Override
+        public boolean isToBeProcessed(CtTypeReference<?> candidate) {
+            return false;
+        }
+
+        @Override
+        public void process(CtTypeReference<?> ignored) {
+            // no-op: this processor works by model-wide traversal in init
+        }
+
+        @Override
+        public void init() {
+            getFactory().getModel().getAllTypes().forEach(type -> {
+                type.getElements(element -> element instanceof CtLocalVariable || element instanceof CtInvocation)
+                        .forEach(this::rewriteElement);
+            });
+        }
+
+        private void rewriteElement(CtElement element) {
+            if (element instanceof CtLocalVariable<?> localVariable) {
+                rewriteLocalVariable(localVariable);
+            } else if (element instanceof CtInvocation<?> invocation) {
+                rewriteInvocation(invocation);
+            }
+        }
+
+        private void rewriteLocalVariable(CtLocalVariable<?> localVariable) {
+            CtExpression<?> defaultExpression = localVariable.getDefaultExpression();
+            if (!(defaultExpression instanceof CtConstructorCall<?> constructorCall)) {
+                return;
+            }
+            if (!isFlywayType(constructorCall.getType())) {
+                return;
+            }
+
+            CtBlock<?> block = localVariable.getParent(CtBlock.class);
+            if (block == null) {
+                return;
+            }
+
+            List<CtInvocation<?>> setters = collectTrailingSetters(block, localVariable);
+            if (setters.isEmpty()) {
+                localVariable.setDefaultExpression(buildConfigureCall(constructorCall, null));
+                return;
+            }
+
+            CtExpression<?> replacement = buildChainedExpression(constructorCall, setters);
+            localVariable.setDefaultExpression(replacement);
+            setters.forEach(CtStatement::delete);
+        }
+
+        private void rewriteInvocation(CtInvocation<?> invocation) {
+            if (!(invocation.getTarget() instanceof CtVariableReadTarget readTarget)) {
+                return;
+            }
+            CtBlock<?> block = invocation.getParent(CtBlock.class);
+            if (block == null) {
+                return;
+            }
+            CtLocalVariable<?> variable = findLocalVariable(block, readTarget.getVariableName());
+            if (variable == null) {
+                return;
+            }
+            CtExpression<?> defaultExpression = variable.getDefaultExpression();
+            if (!(defaultExpression instanceof CtConstructorCall<?> constructorCall)) {
+                return;
+            }
+            if (!isFlywayType(constructorCall.getType())) {
+                return;
+            }
+            if (!isFlywaySetter(invocation)) {
+                return;
+            }
+            // handled when the local variable initializer is rewritten
+            invocation.delete();
+        }
+
+        private CtExpression<?> buildChainedExpression(CtConstructorCall<?> constructorCall, List<CtInvocation<?>> setters) {
+            CtExpression<?> expression = buildConfigureCall(constructorCall, findClassLoaderArgument(setters));
+            for (CtInvocation<?> setter : setters) {
+                if (isClassLoaderSetter(setter)) {
+                    continue;
+                }
+                String fluentName = toFluentName(setter.getExecutable().getSimpleName());
+                CtInvocation<?> chained = getFactory().Code().createInvocation(expression, createExecutableReference(fluentName), setter.getArguments());
+                expression = chained;
+            }
+            return expression;
+        }
+
+        private CtExpression<?> buildConfigureCall(CtConstructorCall<?> constructorCall, CtExpression<?> classLoaderArg) {
+            CtInvocation<?> configure = getFactory().Code().createInvocation(
+                    createTypeReference(OLD_FLYWAY),
+                    createExecutableReference(classLoaderArg == null ? "configure" : "configure"),
+                    classLoaderArg == null ? List.of() : List.of(classLoaderArg)
+            );
+            CtInvocation<?> load = getFactory().Code().createInvocation(configure, createExecutableReference("load"), List.of());
+            return load;
+        }
+
+        private List<CtInvocation<?>> collectTrailingSetters(CtBlock<?> block, CtLocalVariable<?> localVariable) {
+            List<CtStatement> statements = new ArrayList<>(block.getStatements());
+            int index = statements.indexOf(localVariable);
+            if (index < 0) {
+                return List.of();
+            }
+
+            List<CtInvocation<?>> setters = new ArrayList<>();
+            for (int i = index + 1; i < statements.size(); i++) {
+                CtStatement statement = statements.get(i);
+                if (!(statement instanceof CtInvocation<?> invocation)) {
+                    break;
+                }
+                if (!isFlywaySetter(invocation)) {
+                    break;
+                }
+                if (!isInvocationOnVariable(invocation, localVariable.getSimpleName())) {
+                    break;
+                }
+                setters.add(invocation);
+            }
+            return setters;
+        }
+
+        private CtLocalVariable<?> findLocalVariable(CtBlock<?> block, String name) {
+            for (CtStatement statement : block.getStatements()) {
+                if (statement instanceof CtLocalVariable<?> localVariable && name.equals(localVariable.getSimpleName())) {
+                    return localVariable;
+                }
+            }
+            return null;
+        }
+
+        private CtExpression<?> findClassLoaderArgument(List<CtInvocation<?>> setters) {
+            for (CtInvocation<?> setter : setters) {
+                if (isClassLoaderSetter(setter) && !setter.getArguments().isEmpty()) {
+                    return setter.getArguments().get(0);
+                }
+            }
+            return null;
+        }
+
+        private boolean isFlywaySetter(CtInvocation<?> invocation) {
+            String name = invocation.getExecutable().getSimpleName();
+            return Set.of("setDataSource", "setLocations", "setValidateOnMigrate", "setClassLoader").contains(name);
+        }
+
+        private boolean isClassLoaderSetter(CtInvocation<?> invocation) {
+            return "setClassLoader".equals(invocation.getExecutable().getSimpleName());
+        }
+
+        private boolean isInvocationOnVariable(CtInvocation<?> invocation, String variableName) {
+            CtExpression<?> target = invocation.getTarget();
+            return target instanceof spoon.reflect.code.CtVariableRead<?> read && variableName.equals(read.getVariable().getSimpleName());
+        }
+
+        private boolean isFlywayType(CtTypeReference<?> type) {
+            return type != null && OLD_FLYWAY.equals(type.getQualifiedName());
+        }
+
+        private CtExecutableReference<?> createExecutableReference(String simpleName) {
+            CtExecutableReference<?> executable = getFactory().Core().createExecutableReference();
+            executable.setDeclaringType(createTypeReference(NEW_FLYWAY));
+            executable.setSimpleName(simpleName);
+            return executable;
+        }
+
+        private CtTypeReference<Object> createTypeReference(String qualifiedName) {
+            @SuppressWarnings("unchecked")
+            CtTypeReference<Object> type = (CtTypeReference<Object>) getFactory().Type().createReference(qualifiedName);
+            return type;
+        }
+
+        private String toFluentName(String setterName) {
+            if (setterName.startsWith("set") && setterName.length() > 3) {
+                return Character.toLowerCase(setterName.charAt(3)) + setterName.substring(4);
+            }
+            return setterName;
+        }
+    }
+
+    private interface CtVariableReadTarget {
+        String getVariableName();
+    }
+}
*** End Patch

